  name: string;
  preset: MoaPreset;
  /** How the preset was chosen (for logging / user display). */
  method: "explicit" | "embedding" | "fallback";
  /** Set when the requested preset was unavailable and we fell back. */
  note?: string;
}

export async function resolvePreset(cfg: MoaConfig, question: string, explicit?: string): Promise<ResolvedPreset> {
  const usable = (name: string): MoaPreset | null => {
    const p = cfg.presets[name];
    return p && p.enabled !== false ? p : null;
  };
  const fallback = (): ResolvedPreset => ({
    name: "default",
    preset: cfg.presets.default,
    method: "fallback",
  });

  if (explicit) {
    const p = usable(explicit);
    if (p) return { name: explicit, preset: p, method: "explicit" };
    return { ...fallback(), note: `preset「${explicit}」不可用，改用 default` };
  }

  // Embedding-based semantic routing
  const embResult = await routePresetByEmbedding(question);
  if (embResult) {
    const p = usable(embResult);
    if (p) return { name: embResult, preset: p, method: "embedding" };
  }

  const fb = cfg.routing?.fallback_preset;
  if (fb && fb !== "default") {
    const p = usable(fb);
    if (p) return { name: fb, preset: p, method: "fallback" };
  }
  return fallback();
}

