// ── 5. resolvePreset debate/review-panel routing ────────────────────────────
console.log("5. resolvePreset (config-based, no embedding)");
{
  // Explicit preset resolution
  const cfg = validateMoaConfig({
    presets: {
      default: { references: ["a", "b"], enabled: true },
      debate: { references: ["a", "b"], mode: "debate", debate_rounds: 2, enabled: true },
      "review-panel": { references: ["s", "p", "u"], enabled: true },
      "full-panel": { references: ["c", "s", "p", "a"], enabled: true },
    },
    routing: { enabled: true, preset_reprs: {}, fallback_preset: "default" },
  });

  const r1 = await resolvePreset(cfg, "random question", "debate");
  check("explicit debate resolves correctly", r1.name === "debate" && r1.preset.mode === "debate");

  const r2 = await resolvePreset(cfg, "random", "review-panel");
  check("explicit review-panel resolves", r2.name === "review-panel");

  const r3 = await resolvePreset(cfg, "random", "full-panel");
  check("explicit full-panel resolves", r3.name === "full-panel");

  const r4 = await resolvePreset(cfg, "random", "nonexistent");
  check("nonexistent preset fallback to default", r4.name === "default");
  check("fallback has note", r4.note?.includes("不可用") || r4.note?.includes("fallback"));
}

// ── Summary ─────────────────────────────────────────────────────────────────
console.log("");

