toolResponse.originalFile:
// MoA Phase 1 smoke test (SPEC-moa-provider W11) — pure-logic layer.
//
// Verifies:
//   1. validateMoaConfig: invalid presets dropped, missing/disabled default restored
//   2. resolvePreset: explicit / keyword first-match-wins / disabled→fallback / no-match→default
//   3. trimContext: turn windowing + max-chars cap (drop-oldest, oversize tail-truncate)
//   4. buildAggregationPrompt: usable opinions in, skipped refs noted, hint appended
//   5. formatOpinionsMessage: merged single body + route note
//   6. checkMoaAutoTrigger: phrase fire, reason dedup, cooldown, max_per_goal, goal-key reset
//
// Spawn/ACP paths are NOT covered here (needs live harness — manual /moa test).
// Run: node scripts/check-moa.mjs   (requires `npx tsc` build to dist/ first)

import {
  validateMoaConfig,
  resolvePreset,
  trimContext,
  buildAggregationPrompt,
  formatOpinionsMessage,
  checkMoaAutoTrigger,
  _resetAutoTriggerState,
} from "../dist/moa.js";

let failures = 0;
function check(name, cond) {
  if (cond) console.log(`  ✓ ${name}`);
  else { console.error(`  ✗ ${name}`); failures++; }
}

// ── 1. validateMoaConfig ────────────────────────────────────────────────────
console.log("1. validateMoaConfig");
{
  const cfg = validateMoaConfig({
    presets: {
      default: { enabled: false, references: ["a"] },
      broken: { references: [] },
      ok: { references: ["x"] },
    },
  });
  check("disabled default restored from built-in", cfg.presets.default.enabled !== false);
  check("empty-references preset dropped", !cfg.presets.broken);
  check("valid preset kept", !!cfg.presets.ok);
  const cfg2 = validateMoaConfig({});
  check("empty config gets built-in default", Array.isArray(cfg2.presets.default.references));
}

// ── 2. resolvePreset ────────────────────────────────────────────────────────
console.log("2. resolvePreset");
{
  const cfg = validateMoaConfig({
    presets: {
      default: { references: ["a"], enabled: true },
      "red-team": { references: ["b"], enabled: true },
      "fact-check": { references: ["c"], enabled: true },
      dead: { references: ["d"], enabled: false },
    },
    routing: {
      enabled: true,
      rules: [
        { keywords: ["風險", "漏洞"], preset: "red-team" },
        { keywords: ["是什麼", "真的嗎"], preset: "fact-check" },
        { keywords: ["方案", "風險評估報告"], preset: "default" },
      ],
      fallback_preset: "default",
    },
  });
  check("explicit preset honored", resolvePreset(cfg, "x", "fact-check").name === "fact-check");
  const dead = resolvePreset(cfg, "x", "dead");
  check("explicit disabled preset → default + note", dead.name === "default" && !!dead.note);
  const missing = resolvePreset(cfg, "x", "nope");
  check("explicit unknown preset → default + note", missing.name === "default" && !!missing.note);
  check("keyword routes to red-team", resolvePreset(cfg, "這個設計有什麼風險？").name === "red-team");
  check("first-match-wins on overlap (風險 before 方案)", resolvePreset(cfg, "這個方案的風險").name === "red-team");
  check("keyword routes to fact-check", resolvePreset(cfg, "這是真的嗎").name === "fact-check");
  const fb = resolvePreset(cfg, "隨便聊聊天氣");
  check("no keyword match → fallback default", fb.name === "default" && fb.method === "fallback");
  check("routing method reported", resolvePreset(cfg, "有漏洞嗎").method === "keyword");
}

// ── 3. trimContext ──────────────────────────────────────────────────────────
console.log("3. trimContext");
{
  const hist = [];
  for (let i = 0; i < 10; i++) {
    hist.push({ role: "user", text: `question ${i}`, timestamp: i });
    hist.push({ role: "assistant", text: `answer ${i}`, timestamp: i });
  }
  const out = trimContext(hist, 2, 8000);
  check("keeps only last N turns", !out.includes("question 7") && out.includes("question 8") && out.includes("answer 9"));
  check("formats roles", out.includes("User: question 8") && out.includes("Assistant: answer 9"));

  const big = [
    { role: "user", text: "x".repeat(500), timestamp: 0 },
    { role: "assistant", text: "y".repeat(500), timestamp: 1 },
    { role: "user", text: "z".repeat(500), timestamp: 2 },
  ];
  const capped = trimContext(big, 5, 600);
  check("cap drops oldest first", !capped.includes("x") && capped.includes("z"));
  const single = trimContext([{ role: "user", text: "w".repeat(2000), timestamp: 0 }], 5, 300);
  check("oversized single entry tail-truncated", single.length <= 320 && single.includes("…"));
  check("empty history → empty string", trimContext([], 5, 8000) === "");
}

// ── 4. buildAggregationPrompt ───────────────────────────────────────────────
console.log("4. buildAggregationPrompt");
{
  const result = {
    presetName: "default",
    routeMethod: "keyword",
    question: "該用 SQLite 嗎",
    opinions: [
      { name: "moa-ref-claude", status: "ok", text: "可以，理由 A" },
      { name: "moa-ref-kiro", status: "timeout", text: "（逾時未回覆）" },
    ],
  };
  const p = buildAggregationPrompt(result, "比對各顧問");
  check("includes usable opinion", p.includes("可以，理由 A"));
  check("skipped ref noted with status", p.includes("Kiro=timeout"));
  check("timeout text NOT included as opinion", !p.includes("## Kiro:"));
  check("aggregator hint appended", p.includes("比對各顧問"));
  check("question included", p.includes("該用 SQLite 嗎"));
}

// ── 5. formatOpinionsMessage ────────────────────────────────────────────────
console.log("5. formatOpinionsMessage");
{
  const result = {
    presetName: "red-team",
    routeMethod: "fallback",
    routeNote: "preset「dead」不可用，改用 default",
    question: "q",
    opinions: [
      { name: "moa-ref-claude", status: "ok", text: "意見一" },
      { name: "moa-ref-adversary", status: "ok", text: "意見二" },
    ],
  };
  const msg = formatOpinionsMessage(result);
  check("single merged body with both opinions", msg.includes("意見一") && msg.includes("意見二"));
  check("route note surfaced", msg.includes("不可用，改用 default"));
  check("display names used", msg.includes("Devil's Advocate"));
}

// ── 6. checkMoaAutoTrigger guardrails ───────────────────────────────────────
console.log("6. checkMoaAutoTrigger");
{
  _resetAutoTriggerState();
  const goal = (over = {}) => ({
    chat_id: 1, status: "active", objective: "test goal",
    started_at: "2026-07-06T00:00:00Z", reflection_retries: 0, ...over,
  });
  const d1 = await checkMoaAutoTrigger(1, goal(), "我覺得這裡需要第二意見再決定");
  check("exact phrase fires", d1.fire === true && !!d1.reason);
  const d2 = await checkMoaAutoTrigger(1, goal(), "還是需要第二意見");
  check("same reason deduped", d2.fire === false);
  const d3 = await checkMoaAutoTrigger(1, goal({ reflection_retries: 2 }), "卡住了");
  check("different reason blocked by cooldown", d3.fire === false);
  const d4 = await checkMoaAutoTrigger(1, goal(), "普通回覆沒有觸發詞");
  check("no signal → no fire", d4.fire === false);
  const dStale = await checkMoaAutoTrigger(1, goal({ started_at: "2026-07-06T09:99:99Z" }), "需要第二意見");
  check("new goal resets counters (fresh key fires)", dStale.fire === true);
  _resetAutoTriggerState();
}

console.log(failures === 0 ? "\nAll MoA checks passed ✅" : `\n${failures} check(s) FAILED ❌`);
process.exit(failures === 0 ? 0 : 1);

