@echo off
rem Smoke runner. Skips two scripts that aren't part of the automated suite:
rem   check-acp-handshake  — requires an ACP agent argv (manual tool)
rem   check-topic-match    — known pre-existing memory-shard drift, unrelated
rem                          to bridge code; fix via rebuild-topic-shards.mjs
setlocal enabledelayedexpansion
set TOTAL=0
set FAILED=0
set FAIL_LIST=
for %%F in (scripts\check-*.mjs) do (
  set NAME=%%~nF
  if /I "!NAME!"=="check-acp-handshake" (
    echo SKIP !NAME!
  ) else if /I "!NAME!"=="check-topic-match" (
    echo SKIP !NAME!
  ) else (
    set /a TOTAL+=1
    node "%%F" >nul 2>nul
    if !ERRORLEVEL! NEQ 0 (
      set /a FAILED+=1
      set FAIL_LIST=!FAIL_LIST! !NAME!
    ) else (
      echo OK   !NAME!
    )
  )
)
echo.
echo Total: !TOTAL!   Failed: !FAILED!
if !FAILED! GTR 0 echo Failed scripts:!FAIL_LIST!
exit /b !FAILED!

